// Access the generated output from the agent block
const items = $input.all();
if (items.length === 0) return [];

const item = items[0];
const reportText = item.json.output || item.json.text || "";
const context = item.json.context || {};
let currentLoops = context.critic_loops_run || 0;

// Enforce specific validation rules (must contain 'Weekly Performance' and be >= 150 chars)
const hasMarker = reportText.toLowerCase().includes("weekly performance");
const isLongEnough = reportText.length >= 150;

if (!hasMarker || !isLongEnough) {
    currentLoops += 1;

    // Hard break if the agent falls into an infinite loop to prevent API burn
    if (currentLoops >= 4) {
        return [{
            json: {
                passed: false,
                fatalError: true,
                msg: "Max validation attempts reached without passing quality checks. Halting pipeline.",
                critic_loops_run: currentLoops,
                output: reportText
            }
        }];
    }

    let failureReason = "";
    if (!hasMarker) failureReason += "Missing required 'Weekly Performance' heading/section. ";
    if (!isLongEnough) failureReason += `Output is too short (${reportText.length}/150 required characters). `;

    return [{
        json: {
            passed: false,
            critic_loops_run: currentLoops,
            feedback_prompt: `CRITIC FAILURE (Attempt ${currentLoops}/4): Your report was rejected by the Quality Critic. Reason: ${failureReason} Please adjust your parameters, expand on the details, ensure you include the 'Weekly Performance' section, and re-output the full document.`
        }
    }];
}

return [{
    json: {
        passed: true,
        critic_loops_run: currentLoops,
        validated_report: reportText
    }
}];
